code = """import json
import re

with open(locals()['var_function-call-6964896026869671245'], 'r') as f:
    civic_docs = json.load(f)

full_text = chr(10).join([doc['text'] for doc in civic_docs])
full_text_lower = full_text.lower()

# Find all "completed" near "2022"
# Regex: completed.{0,100}2022
matches = re.finditer(r'(completed|completion).{0,100}2022', full_text_lower, re.DOTALL)

print("__RESULT__:")
contexts = []
for m in matches:
    start = max(0, m.start() - 300)
    end = min(len(full_text), m.end() + 100)
    context = full_text[start:end].replace(chr(10), " ")
    contexts.append(context)

print(json.dumps(contexts))"""

